    self.atPlayerId = 0         --目标Id，系统消息传公告Id,(私聊、@功能、回复功能)时传玩家Id，其他为空
    self.atPlayerName = ""      --目标玩家名字，(私聊、@功能、回复功能)时传，其他为空
    self.extraMsg = ""          --需要回复指定的消息内容，回复功能时传，其他为空
    self.sendTime = 0           --发送时间戳，毫秒
    self.head = 0               --玩家头像RefId
    self.headFrame = 0          --玩家头像框RefId
    self.province = 0           --玩家省份
    self.city = 0               --玩家市区
    self.serverId = 0           --玩家服务器Id
    self.scrolling = 0          --是否滚屏
    self.shareType = 0          --分享类型， 1-英雄，
    self.shareData = {}         --分享数据
    self.chatStatus = 0         --聊天状态 0 正常 ；1禁言
    self.grade = 0              --玩家冒险等级
    self.vip = 0                --玩家vip
    self.level = 0              --玩家等级
    self.sex = 0                --性别
    self.title = 0              --称号
    self.tag = {}               --标签
    self.atHead = 0             --目标头像
    self.atHeadFrame = 0        --目标头像框
    self.simulationBattleGroupType = 0          --奥兹模拟赛报名分组类型：1=巅峰赛，2=精英
    self.serverName = ""        --服务器名字
    self.canReceivePlayerIds = ""
    self.roomId = ""            --魔法学院答题室ID
    self.bubble = 0             --聊天气泡
    self.shieldInfo = ""        --屏蔽信息 ， 用|号分割 ，屏蔽Vip显示|屏蔽聊天称号显示 0标识不屏蔽，1标识屏蔽
end

function StructChatMsg:GetMsg()
    if self._bWaitSetMsg then
        local _msg = self.msg
        _msg = LUtil.FilterEmoji(_msg,"?")
        _msg = LWordMaskUtil.ClearShieldWord(_msg,false,nil,true)
        _msg = LUtil.ChatInfoFaceBinToDec(_msg)
        self.msg = _msg
        self._bWaitSetMsg = false
    end
    return self.msg
end

function StructChatMsg:CreateByPb(pb,isSave)
    self.channel = pb.channel
    self.type = pb.type
    local _msg = pb.msg
    self._bWaitSetMsg = false
    if(self.channel ~= ModelChat.CHANNEL_SYSTEM and self.type ~= ModelChat.MSGTYPE_GUILDNOTICE and self.type ~= ModelChat.MSGTYPE_NOTICE and not isSave) then
        self._bWaitSetMsg = true
    end
    if isSave then
        _msg = LUtil.ChatInfoFaceBinToDec(_msg)
    end

