    if(self.channel == ModelChat.CHANNEL_SYSTEM or self.type == ModelChat.MSGTYPE_GUILDNOTICE)then
        local ref = gModelChat:GetMailNoticesRefByRefId(tonumber(self.atPlayerId))
        if ref then
            if(self.playerName == "")then
                self.playerName = ccLngText(ref.name)
